            },
            {
                "old": "// When specified, allowed values are NoSchedule, PreferNoSchedule and NoExecute.",
                "new": "// When specified, allowed values are NoSchedule, PreferNoSchedule, NoScheduleNoTraffic and NoExecute."
            }
        ]
