        "path": "pkg/util/taints/taints.go",
        "changes": [
            {
                "old": '\tif effect != v1.TaintEffectNoSchedule && effect != v1.TaintEffectPreferNoSchedule && effect != v1.TaintEffectNoExecute {',
                "new": '\tif effect != v1.TaintEffectNoSchedule && effect != v1.TaintEffectPreferNoSchedule && effect != v1.TaintEffectNoScheduleNoTraffic && effect != v1.TaintEffectNoExecute {'
            }
        ]
    },
    {
        "path": "staging/src/k8s.io/kubectl/pkg/cmd/taint/utils.go",
        "changes": [
            {
                "old": '\tif effect != corev1.TaintEffectNoSchedule && effect != corev1.TaintEffectPreferNoSchedule && effect != corev1.TaintEffectNoExecute {',
                "new": '\tif effect != corev1.TaintEffectNoSchedule && effect != corev1.TaintEffectPreferNoSchedule && effect != corev1.TaintEffectNoScheduleNoTraffic && effect != corev1.TaintEffectNoExecute {'
            }
        ]
    },
    {
        "path": "pkg/scheduler/framework/plugins/helper/taint.go",
        "changes": [
            {
                "old": '\t\treturn t.Effect == v1.TaintEffectNoSchedule || t.Effect == v1.TaintEffectNoExecute',
                "new": '\t\treturn t.Effect == v1.TaintEffectNoSchedule || t.Effect == v1.TaintEffectNoScheduleNoTraffic || t.Effect == v1.TaintEffectNoExecute'
            }
        ]
    }
]

