package main

import (
	"testing"

	v1 "k8s.io/api/core/v1"
)

// TestNoScheduleNoTrafficTaintEffectExists verifies that the new taint effect is defined
func TestNoScheduleNoTrafficTaintEffectExists(t *testing.T) {
	expectedEffect := v1.TaintEffect("NoScheduleNoTraffic")

	if v1.TaintEffectNoScheduleNoTraffic != expectedEffect {
		t.Errorf("Expected TaintEffectNoScheduleNoTraffic to be %q, got %q", expectedEffect, v1.TaintEffectNoScheduleNoTraffic)
	}
}

// TestNoScheduleNoTrafficTaintCreation verifies that a taint with NoScheduleNoTraffic effect can be created
func TestNoScheduleNoTrafficTaintCreation(t *testing.T) {
	taint := v1.Taint{
		Key:    "dedicated",
		Value:  "special-user",
		Effect: v1.TaintEffectNoScheduleNoTraffic,
	}

	if taint.Effect != v1.TaintEffectNoScheduleNoTraffic {
		t.Errorf("Failed to create taint with NoScheduleNoTraffic effect")
	}

	if string(taint.Effect) != "NoScheduleNoTraffic" {
		t.Errorf("Expected taint effect string to be 'NoScheduleNoTraffic', got %q", taint.Effect)
	}
}

// TestNoScheduleNoTrafficTolerationCreation verifies that a toleration for NoScheduleNoTraffic can be created
func TestNoScheduleNoTrafficTolerationCreation(t *testing.T) {
	toleration := v1.Toleration{
		Key:      "dedicated",
		Operator: v1.TolerationOpEqual,
		Value:    "special-user",
		Effect:   v1.TaintEffectNoScheduleNoTraffic,
	}

	if toleration.Effect != v1.TaintEffectNoScheduleNoTraffic {
		t.Errorf("Failed to create toleration for NoScheduleNoTraffic effect")
	}
}

